void eeTypes_ComplexUnits_Inits() {
  PEETypes eTypes = game_GetEETypes();
  map<UnitClassType, map<UnitType, uint8_t> > *classTreeStructure = eTypes->classTreeStructure;
  map<UnitType, UnitClassType> *parentsClass = eTypes->parentsClass;

  for(auto &it : classDefUnits) {
    for(size_t i = 0, c = it.second.size(); i < c; i++) {
      (*classTreeStructure)[it.first][it.second[i]] = 1;
      (*parentsClass)[it.second[i]] = it.first;
    }
  }
}

void eeTypes_NeutralUnits_Inits() {
  PEETypes eTypes = game_GetEETypes();
  map<NeutralClassType, map<NeutralUnitType, uint8_t> > *classTreeStructure = eTypes->neutralClassTreeStructure;
  map<NeutralUnitType, NeutralClassType> *parentsClass = eTypes->neutralParentsClass;

  for(auto &it : neutralClassDefUnits) {
    for(size_t i = 0, c = it.second.size(); i < c; i++) {
      (*classTreeStructure)[it.first][it.second[i]] = 1;
      (*parentsClass)[it.second[i]] = it.first;
    }
  }
}

void eeTypes_InitUnits() {
  eeTypes_ComplexUnits_Inits();
  eeTypes_NeutralUnits_Inits();
}

NeutralClassType eeTypes_Neutral_Type(NeutralUnitType unitType) {
  PEETypes eTypes = game_GetEETypes();
  map<NeutralUnitType, NeutralClassType> *parentsClass = eTypes->neutralParentsClass;

  if(parentsClass->find(unitType) == parentsClass->end()) {
    return CLASS_NEUTRAL_UNDEFINED;
  }

  return (*parentsClass)[unitType];
}

uint8_t eeTypes_Neutral_IsResource(NeutralUnitType unitType) {
  return eeTypes_Neutral_Type(unitType) == CLASS_FARMABLE_LAND_ANIMALS ||
         eeTypes_Neutral_Type(unitType) == CLASS_STATIC_RESOURCES ||
         unitType == RES_FISH;
}

uint8_t eeTypes_IsFromClass(UnitClassType unitClass, UnitType unitType) {
  PEETypes eTypes = game_GetEETypes();
  map<UnitClassType, map<UnitType, uint8_t> > *classTreeStructure = eTypes->classTreeStructure;

  if(classTreeStructure->find(unitClass) == classTreeStructure->end()) {
    return 0;
  }
  return (*classTreeStructure)[unitClass].find(unitType) != (*classTreeStructure)[unitClass].end();
}

UnitClassType eeTypes_UnitClass(UnitType unitType) {
  PEETypes eTypes = game_GetEETypes();
  map<UnitType, UnitClassType> *parentsClass = eTypes->parentsClass;

  if(parentsClass->find(unitType) == parentsClass->end()) {
    return CLASS_UNDEFINED;
  }

  return (*parentsClass)[unitType];
}

uint8_t eeTypes_IsWaterUnit(UnitType unitType) {
  return eeTypes_IsFromClass(CLASS_WATER_TRANSPORT, unitType) || 
         eeTypes_IsFromClass(CLASS_WATER_CARRIERS, unitType) ||
         eeTypes_IsFromClass(CLASS_WATER_FISHING_BOATS, unitType) ||
         eeTypes_IsFromClass(CLASS_WATER_BOATS, unitType) ||
         eeTypes_IsFromClass(CLASS_SUBMARINES, unitType);
}

uint8_t eeTypes_IsCitizen(UnitType unitType) {
  return eeTypes_IsFromClass(CLASS_CITIZENS, unitType);
}

uint8_t eeTypes_IsWaterTransport(UnitType unitType) {
  return eeTypes_IsFromClass(CLASS_WATER_TRANSPORT, unitType);
}

uint8_t eeTypes_IsTransport(UnitType unitType) {
  return eeTypes_IsWaterUnit(unitType) || eeTypes_IsFromClass(CLASS_SPACE_TRANSPORT, unitType) || eeTypes_IsFromClass(CLASS_AIR_TRANSPORT, unitType);
}

uint8_t eeTypes_IsGroundUnit(UnitType unitType) {
  return eeTypes_IsFromClass(CLASS_GROUND_UNITS, unitType) || 
         eeTypes_IsFromClass(CLASS_CITIZENS, unitType) || 
         eeTypes_IsFromClass(CLASS_HEROES, unitType) ||
         eeTypes_IsFromClass(CLASS_MACHINES, unitType) ||
         eeTypes_IsFromClass(CLASS_SPELL_CASTER, unitType);
}

uint8_t eeTypes_IsFishBoat(UnitType unitType) {
  return eeTypes_IsFromClass(CLASS_WATER_FISHING_BOATS, unitType);
}

uint8_t eeTypes_IsPriest(UnitType type) {
  return type == PRIEST; 
}

uint8_t eeTypes_IsAirUnit(UnitType unitType) {
  return eeTypes_IsFromClass(CLASS_AIR_COMBUSTION_FLYEIR, unitType) ||
         eeTypes_IsFromClass(CLASS_AIR_TRANSPORT, unitType) ||
         eeTypes_IsFromClass(CLASS_AIR_NON_COMBUSTION_FLYER, unitType);
}

uint8_t eeTypes_CanProduceWorkers(UnitType unitType) {
  return unitType == B_TOWN_CENTER || unitType == B_CAPITOL;
}

uint8_t eeTypes_IsBuilding(UnitType unitType) {
  return eeTypes_IsFromClass(CLASS_BUILDINGS, unitType) ||
         eeTypes_IsFromClass(CLASS_TELEPORTER_FORTRESS, unitType) ||
         eeTypes_IsFromClass(CLASS_SPECIAL_BUILDING, unitType) ||
         eeTypes_IsFromClass(CLASS_GATES, unitType);
}